<template><div class="panel"><div class="title">对象详情</div><el-empty v-if="!detail" description="点击地图对象查看详情" /><el-descriptions v-else :column="1" size="small" border><el-descriptions-item v-for="(v,k) in detail" :key="String(k)" :label="String(k)">{{ format(v) }}</el-descriptions-item></el-descriptions></div></template>
<script setup lang="ts">defineProps<{ detail: Record<string, any> | null }>(); function format(v:any){ if(v===null||typeof v==='undefined') return '-'; return typeof v==='object'?JSON.stringify(v):String(v)}</script>
<style scoped>.panel{padding:12px;max-height:calc(100vh - 150px);overflow:auto}.title{font-weight:700;margin-bottom:10px}</style>
